const p = $input.item.json.body;

const isFiring = p.event === 'firing';
const icon     = isFiring ? '\u{1F6A8}' : '\u2705';
const label    = p.event.toUpperCase();
const border   = isFiring ? '#f87171' : '#4ade80';

const sevColor = {
  critical: '#f87171',
  high:     '#fb923c',
  medium:   '#fbbf24',
  low:      '#34d399',
  info:     '#55f3ff',
};
const color = sevColor[p.severity] || '#55f3ff';

const condText = p.condition?.kind === 'threshold'
  ? `${p.condition.agg ?? 'avg'} ${p.condition.op} ${p.condition.value} (last ${p.condition.window_min}min)`
  : `no data (${p.condition?.window_min ?? '?'}min)`;

const rows = [
  p.asset_id  ? `<tr><td style="color:#8892b0;padding:6px 16px 6px 0">Asset</td><td>${p.asset_id}</td></tr>` : '',
  p.namespace ? `<tr><td style="color:#8892b0;padding:6px 16px 6px 0">Namespace</td><td>${p.namespace}</td></tr>` : '',
  p.metric    ? `<tr><td style="color:#8892b0;padding:6px 16px 6px 0">Metric</td><td style="font-family:monospace">${p.metric}</td></tr>` : '',
  `<tr><td style="color:#8892b0;padding:6px 16px 6px 0">Condition</td><td style="font-family:monospace">${condText}</td></tr>`,
  p.value !== null && p.value !== undefined
    ? `<tr><td style="color:#8892b0;padding:6px 16px 6px 0">Value</td><td><b>${Number(p.value).toFixed(2)}</b></td></tr>` : '',
  `<tr><td style="color:#8892b0;padding:6px 16px 6px 0">Severity</td><td><span style="background:${color};color:#040713;padding:2px 8px;border-radius:4px;font-weight:700;font-size:12px">${p.severity?.toUpperCase()}</span></td></tr>`,
  `<tr><td style="color:#8892b0;padding:6px 16px 6px 0">Time</td><td style="font-family:monospace;font-size:12px">${p.fired_at}</td></tr>`,
].filter(Boolean).join('');

const html = `
<div style="background:#040713;padding:24px;font-family:'Inter',-apple-system,sans-serif;color:#e2e8f0">
  <div style="max-width:540px;margin:0 auto;border:1px solid ${border};border-radius:12px;overflow:hidden">
    <div style="background:${border}15;padding:16px 20px;border-bottom:1px solid ${border}40">
      <span style="font-size:20px">${icon}</span>
      <span style="font-size:16px;font-weight:700;margin-left:8px">${label} \u2014 ${p.rule_name}</span>
    </div>
    <div style="padding:16px 20px">
      <table style="border-collapse:collapse;font-size:14px;width:100%">${rows}</table>
    </div>
    <div style="padding:12px 20px;border-top:1px solid #1a2540;font-size:11px;color:#475569">
      Orbit Core Alert System \u2014 via n8n
    </div>
  </div>
</div>`;

return {
  subject: `${icon} ${label} \u2014 ${p.rule_name}`,
  html,
};
